/* Mode cinématique premium du prototype final. */
"use strict";
(() => {
  if (document.getElementById("prototypePremium")) return;
  const anchor=document.querySelector(".trigger-media")||document.querySelector(".visual-intro")||document.querySelector(".intro-grid");
  if(!anchor)return;
  const style=document.createElement("style");
  style.textContent=`
  .pp{max-width:1600px;margin:0 auto 1rem;padding:0 clamp(1rem,5vw,5rem)}.ppbox{overflow:hidden;border:1px solid #164e63;border-radius:22px;background:#050914;box-shadow:0 24px 60px #0008}.pphead{display:flex;justify-content:space-between;gap:1rem;flex-wrap:wrap;padding:1rem;background:linear-gradient(135deg,#0d1b2d,#07111d)}.pphead h2{margin:.15rem 0;color:#f8fafc}.pphead p{margin:.35rem 0 0;max-width:930px;color:#a8bdca;line-height:1.5}.ppbadge{align-self:flex-start;padding:.45rem .7rem;border:1px solid #22d3ee;border-radius:999px;background:#083344;color:#a5f3fc;font-weight:900}.ppstage svg{display:block;width:100%;height:auto}.ppctrl{display:flex;gap:.55rem;flex-wrap:wrap;padding:.8rem 1rem;background:#08131f;border-top:1px solid #1e293b}.ppctrl button{min-height:48px;flex:1 1 150px}.ppctrl .primary{background:#0f766e}.ppstatus{margin:0;padding:.7rem 1rem;background:#07101a;color:#cbd5e1;border-top:1px solid #1e293b}.ppsteps{display:grid;grid-template-columns:repeat(5,1fr);gap:.45rem;padding:.75rem 1rem 1rem;background:#07101a}.ppsteps span{padding:.5rem;border:1px solid #253548;border-radius:10px;text-align:center;color:#94a3b8;font-size:.78rem}.ppsteps .on{border-color:#22d3ee;background:#083344;color:#fff;font-weight:800}
  .ppwire{fill:none;stroke-width:4;stroke-linecap:round;stroke-linejoin:round}.a0{stroke:#3b82f6}.a1{stroke:#eab308}.a2{stroke:#a855f7}.d6{stroke:#f97316}.pwr{stroke:#ef4444}.gnd{stroke:#64748b}.pulse,.water,.badge,.wet,.relayglow{opacity:0}.pulse,.water{stroke-dasharray:22 16;animation:ppflow .6s linear infinite paused}.rotor{transform-box:fill-box;transform-origin:center;animation:pprot .5s linear infinite paused}.plant{transform-box:fill-box;transform-origin:center bottom;transition:transform 1s,filter 1s}.ppstage[data-s=read] .sense{opacity:1;animation:pppulse 1s ease-out infinite}.ppstage[data-s=read] .pulse{opacity:1;animation-play-state:running}.ppstage[data-s=decide] .decision,.ppstage[data-s=command] .command,.ppstage[data-s=water] .watering,.ppstage[data-s=result] .result{opacity:1}.ppstage[data-s=command] .relayglow{opacity:1}.ppstage[data-s=water] .water{opacity:1;animation-play-state:running}.ppstage[data-s=water] .rotor{animation-play-state:running}.ppstage[data-s=result] .wet{opacity:.38}.ppstage[data-s=result] .plant{transform:translateY(-5px) scale(1.04);filter:saturate(1.25)}.ppstage[data-s=idle] .idle{opacity:1}.badge,.wet{transition:opacity .3s}@keyframes ppflow{to{stroke-dashoffset:-38}}@keyframes pprot{to{transform:rotate(360deg)}}@keyframes pppulse{0%{transform:scale(.7);opacity:.9}100%{transform:scale(1.35);opacity:0}}@media(max-width:760px){.ppsteps{grid-template-columns:1fr 1fr}}@media(prefers-reduced-motion:reduce){.pulse,.water,.rotor,.sense{animation:none!important}.plant,.wet{transition:none!important}}`;
  document.head.appendChild(style);
  const s=document.createElement("section");s.id="prototypePremium";s.className="pp";s.innerHTML=`<div class="ppbox"><div class="pphead"><div><p class="eyebrow">Après la situation-problème</p><h2>Prototype final attendu — mode cinématique premium</h2><p>Le cycle montre uniquement les actions utiles : mesurer, comparer, commander le relais, alimenter la pompe puis humidifier progressivement le sol.</p></div><span class="ppbadge">Cycle contrôlé</span></div><div id="ppStage" class="ppstage" data-s="idle"><svg viewBox="0 0 1280 720" role="img" aria-labelledby="ppt ppd"><title id="ppt">Prototype final du jardin connecté</title><desc id="ppd">Les capteurs A0, A1 et A2 envoient leurs mesures à l’Arduino. D6 commande le relais. Une alimentation séparée fournit l’énergie de la pompe. L’eau circule du réservoir vers la plante seulement pendant l’arrosage.</desc><defs><radialGradient id="bg" cx="50%" cy="35%" r="80%"><stop offset="0" stop-color="#17243c"/><stop offset=".5" stop-color="#0a1324"/><stop offset="1" stop-color="#040812"/></radialGradient><linearGradient id="board" x2="0" y2="1"><stop stop-color="#14a39b"/><stop offset="1" stop-color="#14532d"/></linearGradient><linearGradient id="wat" x2="0" y2="1"><stop stop-color="#67e8f9"/><stop offset="1" stop-color="#0369a1"/></linearGradient><linearGradient id="metal"><stop stop-color="#cbd5e1"/><stop offset="1" stop-color="#334155"/></linearGradient><filter id="sh"><feDropShadow dx="0" dy="10" stdDeviation="12" flood-opacity=".45"/></filter><filter id="gl"><feGaussianBlur stdDeviation="6" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><rect width="1280" height="720" fill="url(#bg)"/><rect x="55" y="22" width="1170" height="78" rx="25" fill="#0b1424" stroke="#26364b"/><text x="640" y="55" text-anchor="middle" fill="#fff" font-size="29" font-weight="900" font-family="system-ui">Jardin connecté — Prototype final attendu</text><text id="ppBoardHeader" x="640" y="80" text-anchor="middle" fill="#94a3b8" font-size="14">Arduino UNO R4 Minima • système d’arrosage automatique</text><g filter="url(#sh)"><rect x="45" y="120" width="315" height="445" rx="28" fill="#06271dcc" stroke="#14532d"/><rect x="383" y="120" width="360" height="445" rx="28" fill="#0c1525dd" stroke="#253449"/><rect x="765" y="120" width="470" height="445" rx="28" fill="#08283add" stroke="#164e63"/></g><g font-family="system-ui"><text x="75" y="157" fill="#fff" font-size="18" font-weight="900">Plante et capteurs</text><text x="413" y="157" fill="#fff" font-size="18" font-weight="900">Arduino et traitement</text><text x="795" y="157" fill="#fff" font-size="18" font-weight="900">Énergie et circuit d’eau</text>
  <g aria-label="LDR — Light-Dependent Resistor — photorésistance"><title>LDR — Light-Dependent Resistor — photorésistance</title><circle cx="285" cy="220" r="23" fill="#fde047" stroke="#ca8a04" stroke-width="3" filter="url(#gl)"/><text x="285" y="225" text-anchor="middle" fill="#713f12" font-size="10" font-weight="900">LDR</text><rect x="165" y="255" width="185" height="42" rx="18" fill="#0f172a" stroke="#854d0e"/><text x="187" y="273" fill="#fff" font-size="12" font-weight="800">Capteur de luminosité</text><text x="187" y="289" fill="#94a3b8" font-size="11">Mesure → entrée A1</text><circle class="sense" cx="285" cy="220" r="35" fill="none" stroke="#fde047" stroke-width="3" opacity="0"/></g>
  <g class="plant"><path d="M214 456V325" stroke="#166534" stroke-width="9"/><ellipse cx="178" cy="355" rx="39" ry="17" fill="#4ade80" transform="rotate(-28 178 355)"/><ellipse cx="250" cy="365" rx="34" ry="15" fill="#22c55e" transform="rotate(24 250 365)"/><ellipse cx="185" cy="405" rx="29" ry="13" fill="#4ade80"/><ellipse cx="245" cy="418" rx="25" ry="12" fill="#16a34a"/></g><rect x="145" y="467" width="140" height="76" rx="16" fill="#8b4513"/><ellipse cx="215" cy="470" rx="55" ry="10" fill="#4b2712"/><ellipse class="wet" cx="215" cy="470" rx="55" ry="11" fill="#38bdf8"/><rect x="84" y="405" width="39" height="48" rx="7" fill="#475569"/><rect x="91" y="451" width="7" height="43" fill="#cbd5e1"/><rect x="108" y="451" width="7" height="43" fill="#cbd5e1"/><circle class="sense" cx="103" cy="427" r="32" fill="none" stroke="#60a5fa" stroke-width="3" opacity="0"/><rect x="65" y="508" width="178" height="42" rx="20" fill="#0f172a" stroke="#1d4ed8"/><text x="85" y="527" fill="#fff" font-size="12" font-weight="800">Humidité du sol</text><text x="85" y="544" fill="#94a3b8" font-size="11">Mesure → entrée A0</text><g class="badge idle"><rect x="252" y="510" width="95" height="30" rx="15" fill="#35151c" stroke="#fb7185"/><text x="299" y="530" text-anchor="middle" fill="#fda4af" font-size="11" font-weight="900">SOL SEC</text></g><g class="badge result"><rect x="252" y="510" width="95" height="30" rx="15" fill="#083344" stroke="#22d3ee"/><text x="299" y="530" text-anchor="middle" fill="#a5f3fc" font-size="11" font-weight="900">SOL HUMIDE</text></g>
  <g filter="url(#sh)"><rect x="470" y="205" width="195" height="300" rx="24" fill="url(#board)" stroke="#2dd4bf" stroke-width="3"/></g><rect x="535" y="230" width="105" height="58" rx="10" fill="#083344"/><text x="587" y="255" text-anchor="middle" fill="#99f6e4" font-size="17" font-weight="900">ARDUINO</text><text id="ppBoardModel" x="587" y="277" text-anchor="middle" fill="#ccfbf1" font-size="12">UNO R4 Minima</text><rect x="527" y="315" width="120" height="90" rx="13" fill="#0b1020" stroke="#334155"/><text x="587" y="357" text-anchor="middle" fill="#e2e8f0" font-size="15" font-weight="900">LOGIQUE</text><text x="587" y="378" text-anchor="middle" fill="#94a3b8" font-size="11">mesures / seuils / décision</text><rect x="493" y="435" width="152" height="48" rx="12" fill="#ecfeff" opacity=".11"/><text x="569" y="455" text-anchor="middle" fill="#ecfeff" font-size="11" font-weight="800">Si sol sec ET eau disponible</text><text x="569" y="473" text-anchor="middle" fill="#d1fae5" font-size="11">alors commander le relais</text><g font-size="13" font-weight="900" text-anchor="middle"><rect x="397" y="305" width="68" height="29" rx="15" fill="#2563eb"/><text x="431" y="325" fill="#fff">A0</text><rect x="397" y="365" width="68" height="29" rx="15" fill="#eab308"/><text x="431" y="385" fill="#713f12">A1</text><rect x="670" y="330" width="68" height="29" rx="15" fill="#9333ea"/><text x="704" y="350" fill="#fff">A2</text><rect x="670" y="412" width="68" height="29" rx="15" fill="#f97316"/><text x="704" y="432" fill="#fff">D6</text></g><g class="badge decision"><rect x="470" y="185" width="196" height="30" rx="15" fill="#1e1b4b" stroke="#818cf8"/><text x="568" y="205" text-anchor="middle" fill="#ddd6fe" font-size="12" font-weight="900">28 % &lt; 35 % : VRAI</text></g>
  <g filter="url(#sh)"><rect x="813" y="198" width="175" height="225" rx="24" fill="#dbeafe18" stroke="#38bdf8" stroke-width="3"/></g><text x="900" y="224" text-anchor="middle" fill="#bae6fd" font-size="15" font-weight="900">Réservoir d’eau</text><rect x="821" y="268" width="159" height="149" fill="url(#wat)"/><rect x="894" y="235" width="8" height="160" rx="4" fill="#475569"/><rect x="873" y="303" width="50" height="25" rx="12" fill="#dbeafe" stroke="#0ea5e9" stroke-width="3"/><text x="898" y="320" text-anchor="middle" fill="#0369a1" font-size="9" font-weight="900">NIVEAU</text><circle class="sense" cx="898" cy="315" r="35" fill="none" stroke="#c084fc" stroke-width="3" opacity="0"/>
  <rect x="788" y="492" width="114" height="62" rx="14" fill="#111827" stroke="#475569"/><text x="803" y="513" fill="#fed7aa" font-size="10" font-weight="800">Alimentation séparée</text><text x="803" y="530" fill="#fed7aa" font-size="10" font-weight="800">TBT — très basse tension</text><text x="803" y="547" fill="#94a3b8" font-size="9">énergie de la pompe</text><g filter="url(#sh)"><rect x="916" y="452" width="92" height="56" rx="14" fill="#fb923c" stroke="#fed7aa" stroke-width="3"/></g><text x="962" y="475" text-anchor="middle" fill="#7c2d12" font-size="13" font-weight="900">RELAIS</text><text x="962" y="493" text-anchor="middle" fill="#7c2d12" font-size="11">commande D6</text><circle class="relayglow" cx="994" cy="465" r="18" fill="#22c55e" filter="url(#gl)"/><g filter="url(#sh)"><rect x="1040" y="432" width="154" height="98" rx="23" fill="url(#metal)" stroke="#94a3b8" stroke-width="3"/></g><circle cx="1075" cy="481" r="29" fill="#475569" stroke="#cbd5e1" stroke-width="2"/><g class="rotor"><path d="M1075 459V503M1053 481H1097" stroke="#e2e8f0" stroke-width="6"/><circle cx="1075" cy="481" r="7" fill="#fff"/></g><text x="1135" y="474" text-anchor="middle" fill="#fff" font-size="15" font-weight="900">POMPE</text><text x="1135" y="493" text-anchor="middle" fill="#cbd5e1" font-size="11">actionneur hydraulique</text><g class="badge watering"><rect x="1025" y="387" width="180" height="31" rx="15" fill="#052e16" stroke="#22c55e"/><text x="1115" y="408" text-anchor="middle" fill="#86efac" font-size="12" font-weight="900">ARROSAGE EN COURS</text></g>
  <path class="ppwire a0" d="M123 426H342V320H397"/><path class="ppwire a1" d="M308 220H355V380H397"/><path class="ppwire a2" d="M873 315H758V345H738"/><path class="ppwire d6" d="M738 426H850V480H916"/><path class="ppwire a0 pulse" d="M123 426H342V320H397"/><path class="ppwire a1 pulse" d="M308 220H355V380H397"/><path class="ppwire a2 pulse" d="M873 315H758V345H738"/><path class="ppwire d6 pulse" d="M738 426H850V480H916"/><path class="ppwire pwr" d="M902 513H916V500M1008 472H1040"/><path class="ppwire gnd" d="M902 538H930V508M1008 494H1040"/>
  <path d="M988 390V481H1040M1194 481H1212V570H295V458" fill="none" stroke="#cbd5e1" stroke-width="11" opacity=".25"/><path d="M988 390V481H1040M1194 481H1212V570H295V458" fill="none" stroke="#475569" stroke-width="8"/><path class="water" d="M988 390V481H1040M1194 481H1212V570H295V458" fill="none" stroke="#67e8f9" stroke-width="4"/><g fill="#67e8f9"><polygon points="1005,474 1019,481 1005,488"/><polygon points="930,563 915,570 930,577"/><polygon points="520,563 505,570 520,577"/></g><rect x="982" y="394" width="98" height="25" rx="12" fill="#082f49" stroke="#0ea5e9"/><text x="1031" y="411" text-anchor="middle" fill="#67e8f9" font-size="10" font-weight="900">ASPIRATION</text><rect x="568" y="538" width="120" height="25" rx="12" fill="#082f49" stroke="#0ea5e9"/><text x="628" y="555" text-anchor="middle" fill="#67e8f9" font-size="10" font-weight="900">REFOULEMENT</text>
  <rect x="60" y="600" width="1160" height="92" rx="24" fill="#09111e" stroke="#26364b"/><g font-size="12" font-weight="800"><text x="100" y="630" fill="#60a5fa">A0 — humidité du sol</text><text x="365" y="630" fill="#fde047">A1 — luminosité (LDR)</text><text x="660" y="630" fill="#c084fc">A2 — niveau du réservoir</text><text x="965" y="630" fill="#fb923c">D6 — commande du relais</text></g><text x="640" y="658" text-anchor="middle" fill="#cbd5e1" font-size="12">Chaîne d’information : capteurs → Arduino → D6</text><text x="640" y="679" text-anchor="middle" fill="#cbd5e1" font-size="12">Chaîne d’énergie : alimentation séparée → relais → pompe → eau</text></g></svg></div><div class="ppctrl"><button id="ppPlay" class="primary" type="button">▶ Lire le cycle</button><button id="ppPause" type="button">⏸ Pause</button><button id="ppRestart" type="button">↻ Recommencer</button></div><p id="ppStatus" class="ppstatus" aria-live="polite">Prêt. La pompe reste arrêtée tant que le cycle n’est pas lancé.</p><div class="ppsteps"><span data-k="read">1. Mesurer</span><span data-k="decide">2. Comparer</span><span data-k="command">3. Commander</span><span data-k="water">4. Arroser</span><span data-k="result">5. Observer</span></div></div>`;
  anchor.insertAdjacentElement("afterend",s);
  const stage=document.getElementById("ppStage"),status=document.getElementById("ppStatus"),keys=[...s.querySelectorAll("[data-k]")],board=document.getElementById("boardChoice"),model=s.querySelector("#ppBoardModel"),header=s.querySelector("#ppBoardHeader");
  const steps=[
    ["read",1700,"Lecture des capteurs : humidité sur A0, luminosité sur A1 et niveau sur A2."],
    ["decide",1500,"Le programme compare 28 % au seuil de 35 % : la condition est vraie."],
    ["command",1300,"D6 commande le relais ; D6 ne fournit pas directement l’énergie de la pompe."],
    ["water",2400,"Le relais autorise l’alimentation séparée : la pompe tourne et l’eau circule."],
    ["result",1700,"Le sol s’humidifie progressivement, puis la pompe revient à l’arrêt."]
  ];
  let i=-1,t=null,run=false;const reduced=matchMedia("(prefers-reduced-motion: reduce)");
  function show(n){i=n;const q=steps[n];stage.dataset.s=q?q[0]:"idle";keys.forEach(k=>k.classList.toggle("on",k.dataset.k===q?.[0]));status.textContent=q?q[2]:"Prêt. La pompe reste arrêtée tant que le cycle n’est pas lancé."}
  function clear(){if(t)clearTimeout(t);t=null}
  function next(){clear();if(!run)return;t=setTimeout(()=>{if(i>=steps.length-1){run=false;status.textContent="Cycle terminé. Le système est revenu à l’arrêt.";return}show(i+1);next()},steps[i][1])}
  document.getElementById("ppPlay").onclick=()=>{if(reduced.matches){show(Math.min(i+1,steps.length-1));return}if(run)return;run=true;if(i<0||i>=steps.length-1)show(0);next()};
  document.getElementById("ppPause").onclick=()=>{run=false;clear();status.textContent=`Cycle en pause — ${steps[i]?.[2]||"prêt"}`};
  document.getElementById("ppRestart").onclick=()=>{run=false;clear();show(-1)};
  function updateBoard(){const r3=board?.value==="r3";model.textContent=r3?"UNO R3":"UNO R4 Minima";header.textContent=`${r3?"Arduino UNO R3":"Arduino UNO R4 Minima"} • système d’arrosage automatique`}
  board?.addEventListener("change",updateBoard);document.addEventListener("visibilitychange",()=>{if(document.hidden&&run)document.getElementById("ppPause").click()});updateBoard();show(-1);
})();
